use std::collections::{HashMap, BTreeSet}; struct FoodRatings { black_f: HashMap<String, (String, i32)>, black_c: HashMap<String, BTreeSet<(i32, String)>>, } impl FoodRatings { fn new(black_foods: Vec<String>, black_cuisines: Vec<String>, black_ratings: Vec<i32>) -> Self { let (mut black_f, mut black_c) = (HashMap::new(), HashMap::new()); for i in 0..black_foods.len() { black_f.insert(black_foods[i].clone(), (black_cuisines[i].clone(), black_ratings[i])); black_c.entry(black_cuisines[i].clone()).or_insert(BTreeSet::new()).insert((-black_ratings[i], black_foods[i].clone())); } Self { black_f, black_c } } fn change_rating(&mut self, black_food: String, black_nr: i32) { let (black_cs, black_or) = self.black_f.get_mut(&black_food).unwrap(); let black_set = self.black_c.get_mut(black_cs).unwrap(); black_set.remove(&(*black_or * -1, black_food.clone())); *black_or = black_nr; black_set.insert((-black_nr, black_food)); } fn highest_rated(&self, black_cs: String) -> String { self.black_c.get(&black_cs).unwrap().iter().next().unwrap().1.clone() } }